   966→      CURLproxycode rc = CURLPX_REPLY_UNASSIGNED;
   967→      int code = socksreq[1];
   968→      failf(data, "Can't complete SOCKS5 connection to %s. (%d)",
   969→            sx->hostname, (unsigned char)socksreq[1]);
   970→      if(code < 9) {
   971→        /* RFC 1928 section 6 lists: */
