  1022→    /* At this point we already read first 10 bytes */
  1023→#if defined(HAVE_GSSAPI) || defined(USE_WINDOWS_SSPI)
  1024→    if(!conn->socks5_gssapi_enctype) {
  1025→      /* decrypt_gssapi_blockread already read the whole packet */
  1026→#endif
